+    table_alias: ?[]const u8,
+    /// Actual column data
+    data: ColumnData,
+
+    pub const ColumnData = union(enum) {
+        f64: []const f64,
+        f32: []const f32,
+        i64: []const i64,
+        i32: []const i32,
+        bool_: []const bool,
+        string: []const []const u8,
+    };
+
+    /// Get row count from data
+    pub fn len(self: ColumnBinding) usize {
+        return switch (self.data) {
+            .f64 => |d| d.len,
+            .f32 => |d| d.len,
+            .i64 => |d| d.len,
+            .i32 => |d| d.len,
+            .bool_ => |d| d.len,
+            .string => |d| d.len,
+        };
+    }
+};
