+        if (self.f64) |buf| return buf.len;
+        if (self.f32) |buf| return buf.len;
+        if (self.i64) |buf| return buf.len;
+        if (self.i32) |buf| return buf.len;
+        if (self.bool_) |buf| return buf.len;
