+                .f64 => |d| d,
+                else => return,
+            };
+
+            const out_buf = output.f64 orelse return;
+
+            // Process with or without selection
+            if (selection) |sel| {
+                for (0..selection_len) |i| {
+                    const idx = sel[i];
+                    out_buf[i] = input_data[idx] * 2.0;
+                }
+            } else {
